BEGIN TRANSACTION;
CREATE TABLE applications (
  application_id INTEGER PRIMARY KEY,
  month_date TEXT NOT NULL,
  branch_id INTEGER NOT NULL,
  product_type TEXT NOT NULL,
  stage TEXT NOT NULL,
  requested_amount REAL NOT NULL,
  FOREIGN KEY (branch_id) REFERENCES branches(branch_id)
);
CREATE TABLE branches (
  branch_id INTEGER PRIMARY KEY,
  branch_name TEXT NOT NULL,
  region TEXT NOT NULL
);
CREATE TABLE dim_branch (
    branch_id INTEGER PRIMARY KEY,
    branch_name TEXT NOT NULL,
    region_name TEXT NOT NULL
);
CREATE TABLE dim_product (
    product_id INTEGER PRIMARY KEY,
    product_name TEXT NOT NULL
);
CREATE TABLE fact_current_snapshot (
    as_of_date TEXT NOT NULL,
    branch_id INTEGER NOT NULL,
    product_id INTEGER NOT NULL,
    budgeted_volume_ngn REAL NOT NULL,
    budgeted_disbursement_count INTEGER NOT NULL,
    budgeted_outstanding_loans INTEGER NOT NULL,
    FOREIGN KEY (branch_id) REFERENCES dim_branch(branch_id),
    FOREIGN KEY (product_id) REFERENCES dim_product(product_id)
);
CREATE TABLE fact_monthly_portfolio (
    snapshot_month TEXT NOT NULL,
    branch_id INTEGER NOT NULL,
    product_id INTEGER NOT NULL,
    applications_received INTEGER NOT NULL,
    loans_approved INTEGER NOT NULL,
    loans_disbursed INTEGER NOT NULL,
    disbursed_volume_ngn REAL NOT NULL,
    pending_applications INTEGER NOT NULL,
    postponed_applications INTEGER NOT NULL,
    awaiting_approval INTEGER NOT NULL,
    par1_pct REAL NOT NULL,
    par30_pct REAL NOT NULL,
    par90_pct REAL NOT NULL,
    repeat_customer_number INTEGER NOT NULL,
    repeat_loan_volume_ngn REAL NOT NULL,
    active_loan_officers INTEGER NOT NULL,
    avg_loan_size_ngn REAL NOT NULL,
    avg_product_maturity_months REAL NOT NULL,
    PRIMARY KEY (snapshot_month, branch_id, product_id),
    FOREIGN KEY (branch_id) REFERENCES dim_branch(branch_id),
    FOREIGN KEY (product_id) REFERENCES dim_product(product_id)
);
CREATE TABLE forecast (
  month_date TEXT PRIMARY KEY,
  period_type TEXT NOT NULL,
  projected_disbursement REAL NOT NULL,
  projected_par30 REAL NOT NULL
);
CREATE TABLE monthly_portfolio (
  record_id INTEGER PRIMARY KEY,
  month_date TEXT NOT NULL,
  branch_id INTEGER NOT NULL,
  budget_disbursement REAL NOT NULL,
  actual_disbursement REAL NOT NULL,
  budget_loan_count INTEGER NOT NULL,
  actual_loan_count INTEGER NOT NULL,
  portfolio_outstanding REAL NOT NULL,
  pipeline_amount REAL NOT NULL,
  pending_applications INTEGER NOT NULL,
  approved_applications INTEGER NOT NULL,
  rejected_applications INTEGER NOT NULL,
  FOREIGN KEY (branch_id) REFERENCES branches(branch_id)
);
CREATE TABLE monthly_risk (
  risk_id INTEGER PRIMARY KEY,
  month_date TEXT NOT NULL,
  branch_id INTEGER NOT NULL,
  par30_ratio REAL NOT NULL,
  par90_ratio REAL NOT NULL,
  arrears_amount REAL NOT NULL,
  FOREIGN KEY (branch_id) REFERENCES branches(branch_id)
);
CREATE TABLE officers (
  officer_id INTEGER PRIMARY KEY,
  branch_id INTEGER NOT NULL,
  officer_name TEXT NOT NULL,
  FOREIGN KEY (branch_id) REFERENCES branches(branch_id)
);
CREATE TABLE scenario_results (
  scenario_name TEXT PRIMARY KEY,
  disbursement_impact_pct REAL NOT NULL,
  risk_impact_bps INTEGER NOT NULL,
  liquidity_impact_pct REAL NOT NULL
);
COMMIT;
